INSERT INTO `v1_8b029c3555e82c9cfdc8f6330202d23a2308b2b08dc717921695646f051f06fe` VALUES (0, 0, 0, 0, 0, 112301306, 0, 112301308, 0, "自分を中心とした範囲内の味方の物理攻撃力を特大アップさせ、自分に物理/魔法無効バリアを展開し、目の前の敵１キャラに物理特大ダメージを与え、物理防御力を大ダウンさせる。攻撃時、自分がバリア展開中の場合、さらに自分の物理攻撃力を特大アップし、ダメージは前方の敵が対象になり、物理防御力を一定値無視し、スタンさせる。", 0, 0, 112301310, 0, 0, 0, 0, 0, 112301309, 0.77, 0, 112301304, 112301304, 2001, 112301308, 112301302, 112301303, 0, 0, 112301307, "ピュアリースナイプ+", 0, 0, 0, 1, 0, 0, 0, 112301308, 0, 1123013, 0.0, 0, 0, 0, 112301301, 0, 112301305);
