INSERT INTO `v1_8b029c3555e82c9cfdc8f6330202d23a2308b2b08dc717921695646f051f06fe` VALUES (0, 0, 0, 0, 0, 0, 0, 0, 0, "最も魔法攻撃力が高い味方を中心とした範囲内の味方の魔法攻撃力を大アップ、魔法クリティカルダメージを小アップ、物理防御力を中アップさせ、物理無効バリアを展開する。", 0, 0, 0, 0, 0, 126600301, 0, 0, 0, 1.05, 0, 126600301, 126600304, 2003, 0, 126600302, 126600303, 0, 0, 0, "スパークルミラー", 0, 0, 0, 0, 0, 126600301, 0, 0, 0, 1266003, 0.0, 0, 126600301, 0, 126600301, 0, 126600305);
