INSERT INTO `v1_8b029c3555e82c9cfdc8f6330202d23a2308b2b08dc717921695646f051f06fe` VALUES (0, 0, 0, 0, 0, 132300106, 0, 132300108, 0, "目の前の敵１キャラに対象の物理防御力が魔法防御力より低い場合、物理ダメージ扱いになる魔法特大ダメージを与え、味方全体の魔法攻撃力を特大アップ、魔法クリティカルを大アップ、魔法クリティカルダメージを小アップさせる。発動するたびに、最大２回までダメージが増加し、３回目以降はステータスアップの効果時間が増加する。", 0, 0, 132300110, 0, 0, 132300103, 0, 0, 132300109, 0.0, 0, 0, 132300104, 1003, 132300108, 132300102, 132300103, 0, 0, 132300107, "究極錬成‐氷炎融合", 0, 0, 0, 0, 0, 0, 0, 132300108, 0, 1323001, 0.0, 0, 132300102, 0, 132300101, 0, 132300105);
