INSERT INTO `v1_8b029c3555e82c9cfdc8f6330202d23a2308b2b08dc717921695646f051f06fe` VALUES (0, 0, 0, 0, 134000301, 134000306, 0, 0, 0, "味方全体の物理・魔法攻撃力を大アップ、物理・魔法クリティカルダメージを小アップさせる。この効果はバリア展開中の味方に対して効果量が増加する。風属性の味方のＴＰを中回復させる。", 0, 0, 134000310, 0, 134000306, 134000302, 0, 0, 134000309, 1.05, 0, 134000302, 134000304, 2003, 134000308, 134000302, 134000303, 0, 0, 134000307, "ファータ・パルピト", 0, 0, 0, 0, 0, 134000301, 0, 134000306, 0, 1340003, 0.0, 0, 134000302, 0, 134000301, 134000306, 134000305);
