INSERT INTO `v1_8b029c3555e82c9cfdc8f6330202d23a2308b2b08dc717921695646f051f06fe` VALUES (0, 0, 0, 0, 134300101, 134300106, 0, 0, 0, "最も魔法防御力が低い敵を中心とした範囲内の敵に魔法特大ダメージを与え、魔法防御力を中ダウンさせる。さらに追加で魔法特大ダメージを与える。範囲内の敵の数に応じて、ダメージが減少する。", 0, 0, 0, 0, 0, 134300102, 0, 0, 0, 0.0, 0, 134300101, 134300104, 1002, 0, 134300102, 134300103, 0, 0, 0, "ルベライトシンフォニー", 0, 0, 0, 0, 0, 134300101, 0, 0, 0, 1343001, 0.0, 0, 134300101, 0, 134300101, 0, 134300105);
