INSERT INTO `v1_8b029c3555e82c9cfdc8f6330202d23a2308b2b08dc717921695646f051f06fe` VALUES (0, 0, 0, 0, 0, 134900106, 0, 0, 0, "目の前の敵１キャラに物理極大ダメージを与え、魔法攻撃力を大ダウン、物理防御力を中ダウンさせる。自分の物理攻撃力と物理クリティカルを特大アップするが、自分の最大ＨＰの10％を消費する。このスキルによる自分へのダメージでは自分のＴＰは回復しない。【お堪忍袋】付与中、【お堪忍袋】を１個消費し、さらに追加で自分の物理攻撃力を特大アップする。", 0, 0, 0, 0, 0, 0, 0, 0, 134900109, 0.0, 0, 0, 134900104, 1001, 134900108, 134900102, 134900103, 0, 0, 134900107, "マンティコア流操霊術・ハイドラカノン", 0, 0, 0, 0, 0, 134900101, 0, 134900108, 0, 1349001, 0.0, 0, 134900101, 0, 134900101, 0, 134900105);
