INSERT INTO `v1_8b029c3555e82c9cfdc8f6330202d23a2308b2b08dc717921695646f051f06fe` VALUES (0, 0, 0, 0, 0, 433801306, 0, 0, 0, "目の前の敵１キャラを中心とした範囲内の敵すべてに魔法大ダメージを与え、ＴＰを小ダウンさせ、グレゴールのＨＰとＴＰを小回復する。また、グレゴール以外の味方すべての魔法攻撃力と魔法クリティカルを大アップさせる。グレゴール以外の闇属性のキャラに対してはこの効果が２回発動する。", 0, 0, 0, 0, 0, 0, 0, 0, 433801309, 1.0, 0, 0, 433801304, 2002, 433801308, 433801302, 433801303, 0, 0, 433801307, "妖精の羽ばたき", 0, 0, 0, 0, 0, 433801301, 0, 0, 0, 4338013, 0.0, 0, 433801302, 0, 433801301, 0, 433801305);
